package com.cho2hand.marketplace.service.impl.chat;
import com.cho2hand.marketplace.dto.chat.*;import com.cho2hand.marketplace.entity.chat.*;import com.cho2hand.marketplace.exception.*;import com.cho2hand.marketplace.repository.chat.*;import com.cho2hand.marketplace.repository.listing.ListingRepository;import com.cho2hand.marketplace.repository.user.UserRepository;import com.cho2hand.marketplace.service.chat.ChatService;import com.cho2hand.marketplace.service.notification.NotificationService;import java.time.Instant;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service @Transactional public class ChatServiceImpl implements ChatService{private final ConversationRepository conversations;private final MessageRepository messages;private final ListingRepository listings;private final UserRepository users;private final NotificationService notifications;public ChatServiceImpl(ConversationRepository c,MessageRepository m,ListingRepository l,UserRepository u,NotificationService n){conversations=c;messages=m;listings=l;users=u;notifications=n;}public Long open(Long buyer,Long listingId){var listing=listings.findById(listingId).filter(v->v.getArchivedAt()==null).orElseThrow(()->new ListingNotFoundException(listingId));if(buyer.equals(listing.getSellerUserId()))throw new ListingAccessDeniedException();return conversations.findByListingIdAndBuyerUserIdAndSellerUserId(listingId,buyer,listing.getSellerUserId()).orElseGet(()->{var c=new Conversation();c.setListingId(listingId);c.setBuyerUserId(buyer);c.setSellerUserId(listing.getSellerUserId());return conversations.save(c);}).getId();}@Transactional(readOnly=true) public List<ConversationResponse> conversations(Long user){return conversations.findByBuyerUserIdOrSellerUserIdOrderByLastMessageAtDesc(user,user).stream().map(c->new ConversationResponse(c.getId(),c.getListingId(),c.getBuyerUserId(),c.getSellerUserId(),c.getLastMessageAt())).toList();}public MessageResponse send(Long user,Long id,SendMessageRequest r){var c=participant(user,id);var m=new Message();m.setConversationId(c.getId());m.setSenderUserId(user);m.setBody(r.body().trim());m=messages.save(m);c.setLastMessageAt(Instant.now());var sender=users.findById(user).map(v->v.getDisplayName()).orElse("Người dùng OldMarket");notifications.create(user.equals(c.getBuyerUserId())?c.getSellerUserId():c.getBuyerUserId(),"MESSAGE","Tin nhắn mới từ "+sender,"/chat?conversation="+c.getId());return response(m);}@Transactional(readOnly=true) public List<MessageResponse> messages(Long user,Long id){participant(user,id);return messages.findByConversationIdOrderBySentAtAsc(id).stream().map(this::response).toList();}private Conversation participant(Long user,Long id){var c=conversations.findById(id).orElseThrow(()->new ConversationNotFoundException(id));if(!user.equals(c.getBuyerUserId())&&!user.equals(c.getSellerUserId()))throw new ListingAccessDeniedException();return c;}private MessageResponse response(Message m){return new MessageResponse(m.getId(),m.getSenderUserId(),m.getBody(),m.getSentAt());}}
